parameters.jsCode:
function stripMarkdownFences(value) {
  return String(value || '')
    .trim()
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

function safeJsonParse(value) {
  const cleaned = stripMarkdownFences(value);
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) {
      return JSON.parse(match[0]);
    }
    throw error;
  }
}

function toScore(value) {
  const number = Number(value);
  if (!Number.isFinite(number)) return null;
  return Math.max(0, Math.min(100, number));
}

return $input.all().map((item) => {
  const input = item.json;
  let review;
  let parseError = null;

  try {
    review = safeJsonParse(input.gemini_review_raw);
  } catch (error) {
    parseError = error.message;
    review = {
      critique: input.gemini_review_raw || 'Gemini review was empty or unavailable.',
      strengths: [],
      risks: ['Review JSON could not be parsed.'],
      revision_suggestions: ['Re-run Gemini review or inspect the raw response.']
    };
  }

  const scoreKeys = ['technical_accuracy', 'clarity', 'audience_fit', 'originality', 'actionability', 'brand_safety'];
  const scores = {};
  for (const key of scoreKeys) {
    const value = review[key] ?? review.scores?.[key];
    const score = toScore(value);
    if (score !== null) scores[key] = score;
  }

  let overallScore = toScore(review.overall_score ?? review.scores?.overall_score);
  if (overallScore === null) {
    const values = Object.values(scores);
    overallScore = values.length ? Math.round(values.reduce((sum, score) => sum + score, 0) / values.length) : 0;
  }

  const threshold = Number(input.quality_threshold || 80);
  const criticalFailures = Object.entries(scores)
    .filter(([, score]) => score < 60)
    .map(([key, score]) => `${key}: ${score}`);
  const passed = parseError === null && overallScore >= threshold && criticalFailures.length === 0;

  return {
    json: {
      content_type: input.content_type,
      refined_content: input.refined_content,
      gemini_review_raw: input.gemini_review_raw,
      review,
      evaluation: {
        threshold,
        overall_score: overallScore,
        category_scores: scores,
        critical_failures: criticalFailures,
        passed,
        decision: passed ? 'READY_FOR_HUMAN_APPROVAL' : 'REJECT_OR_REVISE',
        parse_error: parseError
      },
      slack_webhook_url: input.slack_webhook_url,
      approval_callback_url: input.approval_callback_url
    }
  };
});

return $input.all().map((item) => {
  const data = item.json;
  const scores = data.evaluation.category_scores || {};
  const scoreLines = Object.entries(scores).map(([key, value]) => `* ${key}: ${value}`).join('\n') || '* No category scores available';
  const critique = data.review.critique || data.review.summary || 'No critique provided.';
  const suggestions = Array.isArray(data.review.revision_suggestions)
    ? data.review.revision_suggestions.join('\n- ')
    : String(data.review.revision_suggestions || 'No revision suggestions provided.');

  return {
    json: {
      slack_webhook_url: data.slack_webhook_url,
      payload: {
        text: `Content ready for human approval: ${data.evaluation.overall_score}/100`,
        blocks: [
          {
            type: 'header',
            text: {
              type: 'plain_text',
              text: 'Content ready for human approval'
            }
          },
          {
            type: 'section',
            fields: [
              {
                type: 'mrkdwn',
                text: `*Content type:*\n${data.content_type}`
              },
              {
                type: 'mrkdwn',
                text: `*Overall score:*\n${data.evaluation.overall_score}/${data.evaluation.threshold}`
              }
            ]
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Category scores:*\n${scoreLines}`
            }
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Gemini critique:*\n${critique}`
            }
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Revision suggestions:*\n- ${suggestions}`
            }
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Final draft:*\n${data.refined_content.slice(0, 2500)}`
            }
          }
        ]
      }
    }
  };
});

return $input.all().map((item) => {
  const data = item.json;
  const failures = data.evaluation.critical_failures.length
    ? data.evaluation.critical_failures.join(', ')
    : data.evaluation.parse_error || 'Overall score below threshold';
  const suggestions = Array.isArray(data.review.revision_suggestions)
    ? data.review.revision_suggestions.join('\n- ')
    : String(data.review.revision_suggestions || 'No revision suggestions provided.');

  return {
    json: {
      slack_webhook_url: data.slack_webhook_url,
      payload: {
        text: `Content needs revision: ${data.evaluation.overall_score}/100`,
        blocks: [
          {
            type: 'header',
            text: {
              type: 'plain_text',
              text: 'Content needs revision'
            }
          },
          {
            type: 'section',
            fields: [
              {
                type: 'mrkdwn',
                text: `*Content type:*\n${data.content_type}`
              },
              {
                type: 'mrkdwn',
                text: `*Score / threshold:*\n${data.evaluation.overall_score}/${data.evaluation.threshold}`
              }
            ]
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Reason:*\n${failures}`
            }
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Suggested revisions:*\n- ${suggestions}`
            }
          }
        ]
      }
    }
  };
});

return $input.all().map((item) => {
  const error = item.json;
  const configuredWebhook = $('Configure Content Input').first()?.json?.slack_webhook_url;
  return {
    json: {
      slack_webhook_url: configuredWebhook || 'REPLACE_WITH_SLACK_INCOMING_WEBHOOK_URL',
      payload: {
        text: 'LLM-as-Judge workflow error',
        blocks: [
          {
            type: 'header',
            text: {
              type: 'plain_text',
              text: 'LLM-as-Judge workflow error'
            }
          },
          {
            type: 'section',
            fields: [
              {
                type: 'mrkdwn',
                text: `*Workflow:*\n${error.workflow?.name || 'Unknown'}`
              },
              {
                type: 'mrkdwn',
                text: `*Failed node:*\n${error.execution?.lastNodeExecuted || 'Unknown'}`
              }
            ]
          },
          {
            type: 'section',
            text: {
              type: 'mrkdwn',
              text: `*Error:*\n${error.execution?.error?.message || error.message || 'Unknown error'}`
            }
          }
        ]
      }
    }
  };
});
